--- WINGs/wwindow.c.orig        2008-02-05 15:53:08.000000000 +0900
+++ WINGs/wwindow.c     2008-02-05 15:50:18.000000000 +0900
@@ -254,14 +254,14 @@
 setMiniwindow(WMWindow *win, RImage *image)
 {
     WMScreen *scr= win->view->screen;
-    CARD32 *data;
+    unsigned long *data;
     int x, y;
     int o;
